/opt/conda/bin/python3 -c '
import json
from pathlib import Path


def load_json(path):
    try:
        with open(path, "r", encoding="utf-8") as f:
            return json.load(f)
    except Exception:
        return []

output = {
    "status": "success",
    "artifacts": {
        "network_connections": load_json("/tmp/netscan.json"),
        "process_list": load_json("/tmp/pslist.json"),
        "injected_memory": load_json("/tmp/malfind.json"),
    },
}

output_path = Path("/data/output/triage_lockdown_report.json")
output_path.parent.mkdir(parents=True, exist_ok=True)
with open(output_path, "w", encoding="utf-8") as out_file:
    json.dump(output, out_file, indent=2)

print(json.dumps(output))
'

parameters.jsCode:
const results = [];

for (const item of $input.all()) {
  if (item.json.error && !item.json.stdout) {
    results.push({ json: { status: "failed", raw_error: item.json.error.message } });
    continue;
  }

  try {
    const parsedData = JSON.parse(item.json.stdout);
    results.push({ json: parsedData });
  } catch (err) {
    results.push({ json: { status: "parsing_error", raw_stdout: item.json.stdout } });
  }
}

return results;
